=$page.setDefaultNavigationTimeout(240000);
const CREDS = require('/home/node/.n8n/nodes/node_modules/creds.js');

function isCookieExpired(cookie) {
  if (!cookie) return true;
  if (cookie.expires === -1) return false;
  return cookie.expires < (Date.now() / 1000);
}

const url = '{{ $('Start').item.json.login_url }}';

async function getTargetCookie(cookieName) {
  const cookies = await $page.cookies(url);
  return cookies.find(cookie => cookie.name === cookieName);
}

const loginCookieName = '{{ $('Start').item.json.login_cookie_name }}';
let targetCookie = await getTargetCookie(loginCookieName);

let loginTriggered = isCookieExpired(targetCookie);
if (loginTriggered) {
  const account = CREDS['{{ $('Start').item.json.host }}'];

  await $page.goto(url, { waitUntil: 'domcontentloaded' });
  await $page.waitForSelector('{{ $('Start').item.json.login_form_selector }}', { timeout: 30000 });
  await $page.type('{{ $('Start').item.json.login_form_selector }}', account.login);
  await $page.type('{{ $('Start').item.json.password_form_selector }}', account.password);
  await $page.click('{{ $('Start').item.json.login_button_selector }}');
  await $page.waitForSelector('{{ $('Start').item.json.success_login_selector }}', { timeout: 30000 });

  targetCookie = await getTargetCookie(loginCookieName);
}

await $page.goto('{{ $('Start').item.json.link }}', { waitUntil: 'domcontentloaded' });
await $page.waitForSelector('{{ $('Start').item.json.phone_button_selector }}', { timeout: 30000 });
await $page.click('{{ $('Start').item.json.phone_button_selector }}');

let phoneTimeout = false;
try {
    await $page.waitForSelector('{{ $('Start').item.json.phone_form_selector }}', { timeout: 30000, visible: true });
} catch (error) {
    phoneTimeout = true;
}

const pageContent = await $page.content();

return [{
  json: {
    login_cookie_name: loginCookieName,
    is_update_cookie_triggered: loginTriggered,
    login_expires: DateTime.fromMillis(targetCookie.expires * 1000).toFormat('yyyy-MM-dd HH:mm:ss'),
    data: pageContent,
    is_get_phone_timeout: phoneTimeout
  }
}];
